const all = $input.all();
const wellness = all[0].json;
const activities = all.slice(1).map(i => i.json);

let totalCalories = 0;
let avgHRSum = 0;
let avgHRCount = 0;
const workoutNames = [];

for (const act of activities) {
  if (act.calories)          totalCalories += act.calories;
  if (act.average_heartrate) {
    avgHRSum   += act.average_heartrate;
    avgHRCount += 1;
  }
  if (act.name) workoutNames.push(`${act.name} (${act.type})`);
}

const sleepHours = wellness.sleepSecs
  ? Math.round((wellness.sleepSecs / 3600) * 100) / 100
  : null;

return [{
  json: {
    report_date:     wellness.id,
    steps:           wellness.steps        ?? null,
    resting_hr:      wellness.restingHR    ?? null,
    hrv_avg:         wellness.hrv          ?? null,
    hrv_min:         null,
    hrv_max:         null,
    spo2_avg:        wellness.spO2         ?? null,
    spo2_min:        null,
    sleep_hours:     sleepHours,
    sleep_deep_min:  null,
    sleep_rem_min:   null,
    sleep_light_min: null,
    sleep_awake_min: null,
    calories:        totalCalories         || null,
    distance_km:     null,
    resp_rate:       wellness.respiration  ?? null,
    sleep_score:     wellness.sleepScore   ?? null,
    sleep_quality:   wellness.sleepQuality ?? null,
    weight:          wellness.weight       ?? null,
    workout_count:   activities.length,
    workout_names:   workoutNames.join(', ') || 'Rest day',
    workout_avg_hr:  avgHRCount > 0
                       ? Math.round(avgHRSum / avgHRCount)
                       : null,
    atl:             wellness.atl          ?? null,
    atl_load:        wellness.atlLoad      ?? null,
  }
}];

const geminiRaw = $input.first().json;
const prevData = $('Build Gemini Prompt').first().json;

const rawContent = geminiRaw?.choices?.[0]?.message?.content ?? null;
const rawReasoning = geminiRaw?.choices?.[0]?.message?.reasoning ?? '';
const rawText = (rawContent && rawContent.trim().length > 50) ? rawContent : rawReasoning;

const aiText = rawText
  .replace(/<think>[\s\S]*?</think>/gi, '')
  .replace(/^(Let me|I need|We need|First,|Now,|Let's|Okay,|Alright,|Looking at|I'll|I will|I should|So I|To output|Must |Section \d|Count:|That's \d|Total \d|We need to|I'm going|Going to|Need to|Let me think|Thinking|Draft|Output|Words:|Let me draft|Here's my|Craft:|So the|Let me now|Now I|Now let|So for|For section|Now section|Candidates:|Let's pick|Pick:|Choose:|Must be|Must pick|Must match|Must output|Must include|Must use|Must speak|Must write|Must have|Must give|Must recommend|Must mention|Must say|Must avoid|Must not|Must never|Rules:|Rule:|Format:|Note:|Notes:|Eg |E.g|Example:|Examples:|Let me craft|So section|So we need|Second line|First line|Two lines|Both lines|Each line|Line \d|Next section|Previous section).*$/gim, '')
  .replace(/
{3,}/g, '

')
  .trim();

const d = prevData;
const reportDate = d.report_date ? d.report_date.toString().substring(0, 10) : 'N/A';

const sleepQualityMap = { 1: 'Excellent', 2: 'Good', 3: 'Fair', 4: 'Poor', 5: 'Very Poor' };
const sleepQualityLabel = d.sleep_quality ? (sleepQualityMap[d.sleep_quality] ?? d.sleep_quality) : '—';

const todayObj = new Date();
const todayStr = todayObj.toISOString().split('T')[0];
const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const todayName = dayNames[todayObj.getDay()];

const workoutSplit = {
  Monday: 'Chest & Triceps', Tuesday: 'Back & Biceps', Wednesday: 'Shoulders',
  Thursday: 'Legs', Friday: 'Full Upper Body', Saturday: 'Legs + Shoulders + HIIT', Sunday: 'Morning Run'
};
const todaySession = workoutSplit[todayName] || 'Rest';

const stepsColor = d.steps >= 8000 ? '#22c55e' : d.steps >= 5000 ? '#f59e0b' : '#ef4444';
const hrvColor   = d.hrv_avg >= 60  ? '#22c55e' : d.hrv_avg >= 40  ? '#f59e0b' : '#ef4444';
const sleepColor = d.sleep_score >= 80 ? '#22c55e' : d.sleep_score >= 60 ? '#f59e0b' : '#ef4444';
const stepsGoalPct = d.steps ? Math.min(Math.round((d.steps / 9000) * 100), 100) : 0;

const aiSections = aiText
  .split('
')
  .filter(l => l.trim())
  .map(line => {
    const trimmed = line.trim();
    const isHeader = /^[1-9]\.\s+[^\w]/.test(trimmed) || /^[\u{1f300}-\u{1f9ff}]/.test(trimmed);
    if (isHeader) {
      return `<div style="font-weight:600;font-size:14px;color:#1e293b;margin:16px 0 5px;padding-bottom:5px;border-bottom:1px solid #e2e8f0">${trimmed}</div>`;
    }
    if (trimmed.startsWith('🎥')) {
      return `<div style="background:#fff7ed;border-radius:6px;padding:8px 12px;margin:4px 0;border:1px solid #fed7aa;font-size:13px;color:#9a3412;line-height:1.6">${trimmed}</div>`;
    }
    if (trimmed.startsWith('•') || trimmed.startsWith('-')) {
      return `<div style="font-size:13px;color:#475569;line-height:1.7;padding-left:12px;margin:2px 0">${trimmed}</div>`;
    }
    return `<div style="font-size:13px;color:#475569;line-height:1.7;margin:3px 0">${trimmed}</div>`;
  }).join('');

const htmlEmail = `<html><body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;background:#f1f5f9;padding:24px;margin:0">
<div style="max-width:620px;margin:0 auto">
  <div style="background:#0f172a;border-radius:16px 16px 0 0;padding:28px 24px;text-align:center">
    <div style="font-size:28px;margin-bottom:6px">🏋️</div>
    <h1 style="margin:0;color:#f8fafc;font-size:20px;font-weight:600">Kunal's Daily Health Brief</h1>
    <p style="margin:6px 0 0;color:#94a3b8;font-size:12px;letter-spacing:0.5px;text-transform:uppercase">${reportDate} · Amazfit Helio → AI Coach</p>
  </div>
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#1d4ed8">
    <tr>
      <td style="padding:12px 24px;color:#bfdbfe;font-size:11px;text-transform:uppercase">Today's session — ${todayName}</td>
      <td style="padding:12px 24px;color:#ffffff;font-size:13px;font-weight:500;text-align:right">💪 ${todaySession}</td>
    </tr>
  </table>
  <div style="background:#ffffff;padding:20px;border-left:1px solid #e2e8f0;border-right:1px solid #e2e8f0">
    <div style="font-size:10px;text-transform:uppercase;color:#94a3b8;margin-bottom:12px">Yesterday's biometrics</div>
    <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:8px">
      <tr>
        <td width="33%" style="padding-right:4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">Steps</div><div style="font-size:22px;font-weight:600;color:${stepsColor}">${d.steps?.toLocaleString() ?? '—'}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">goal: 9,000</div></div></td>
        <td width="33%" style="padding:0 4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">Calories</div><div style="font-size:22px;font-weight:600;color:#1e293b">${d.calories ?? '—'}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">kcal burned</div></div></td>
        <td width="33%" style="padding-left:4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">Resting HR</div><div style="font-size:22px;font-weight:600;color:#ef4444">${d.resting_hr ?? '—'}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">bpm</div></div></td>
      </tr>
    </table>
    <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:16px">
      <tr>
        <td width="33%" style="padding-right:4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">HRV</div><div style="font-size:22px;font-weight:600;color:${hrvColor}">${d.hrv_avg ?? '—'}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">ms rmssd</div></div></td>
        <td width="33%" style="padding:0 4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">Sleep</div><div style="font-size:22px;font-weight:600;color:#6366f1">${d.sleep_hours ?? '—'}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">hours</div></div></td>
        <td width="33%" style="padding-left:4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">Sleep score</div><div style="font-size:22px;font-weight:600;color:${sleepColor}">${d.sleep_score ?? '—'}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">/ 100</div></div></td>
      </tr>
    </table>
    <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:16px">
      <tr>
        <td width="33%" style="padding-right:4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">Workout HR</div><div style="font-size:22px;font-weight:600;color:#1e293b">${d.workout_avg_hr ?? '—'}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">avg bpm</div></div></td>
        <td width="33%" style="padding:0 4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">Weight</div><div style="font-size:22px;font-weight:600;color:#1e293b">${d.weight ?? '—'}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">kg</div></div></td>
        <td width="33%" style="padding-left:4px"><div style="background:#f8fafc;border-radius:10px;padding:14px 8px;text-align:center;border:1px solid #e2e8f0"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;margin-bottom:4px">Sessions</div><div style="font-size:22px;font-weight:600;color:#1e293b">${d.workout_count ?? 0}</div><div style="font-size:9px;color:#94a3b8;margin-top:3px">workouts</div></div></td>
      </tr>
    </table>
    <table style="margin-bottom:16px" width="100%">
      <tr>
        <td style="font-size:11px;color:#64748b">Steps progress toward 9,000 goal</td>
        <td style="font-size:11px;font-weight:500;color:${stepsColor};text-align:right">${stepsGoalPct}%</td>
      </tr>
    </table>
    <div style="background:#e2e8f0;border-radius:99px;height:6px;margin-bottom:16px">
      <div style="background:${stepsColor};height:6px;border-radius:99px;width:${stepsGoalPct}%"></div>
    </div>
    ${d.workout_names && d.workout_names !== 'Rest day' ? `<div style="background:#fef3c7;border-radius:8px;padding:10px 14px;margin-bottom:8px;border:1px solid #fde68a"><div style="font-size:11px;color:#92400e;text-transform:uppercase">Yesterday's workouts</div><div style="font-size:13px;color:#78350f;font-weight:500;margin-top:3px">🏋️ ${d.workout_names}</div></div>` : ''}
  </div>
  <div style="background:#ffffff;border:1px solid #e2e8f0;border-top:none;padding:20px">
    <div style="font-size:10px;text-transform:uppercase;color:#94a3b8;margin-bottom:14px">AI coach brief — ${todayName}, ${todayStr}</div>
    <div style="background:#f8fafc;border-radius:10px;padding:16px;border:1px solid #e2e8f0">${aiSections}</div>
  </div>
  <div style="background:#0f172a;border-radius:0 0 16px 16px;padding:14px 24px;text-align:center">
    <p style="margin:0;color:#475569;font-size:11px">Amazfit Helio → Zepp → Intervals.icu → n8n → AI → You</p>
  </div>
</div></body></html>`;

const safeTelegramAi = aiText
  .replace(/\*\*(.*?)\*\*/g, '$1')
  .replace(/\*(.*?)\*/g, '$1')
  .replace(/_(.*?)_/g, '$1')
  .replace(/\[(.*?)\]\((.*?)\)/g, '$1 → $2')
  .replace(/#{1,6}\s/g, '')
  .replace(/[*_`]/g, '')
  .trim();

const telegramMsg = `💪 *Kunal's Health Brief — ${reportDate}*
📅 Today: *${todayName}* → ${todaySession}

*Yesterday's Numbers*
👟 Steps: ${d.steps?.toLocaleString() ?? 'N/A'} ${d.steps >= 8000 ? '✅' : d.steps >= 5000 ? '⚠️' : '❌'} _(goal: 9,000)_
🔥 Calories: ${d.calories ?? 'N/A'} kcal
❤️ Resting HR: ${d.resting_hr ?? 'N/A'} bpm
🧠 HRV: ${d.hrv_avg ?? 'N/A'} ms ${d.hrv_avg >= 60 ? '✅' : d.hrv_avg >= 40 ? '⚠️' : '❌'}
💤 Sleep: ${d.sleep_hours ?? 'N/A'}h · Score: ${d.sleep_score ?? 'N/A'}/100 · ${sleepQualityLabel}
🏋️ Workouts: ${d.workout_count ?? 0} session(s)${d.workout_names && d.workout_names !== 'Rest day' ? ` — ${d.workout_names}` : ''}
⚖️ Weight: ${d.weight ?? 'N/A'} kg

━━━━━━━━━━━━━━━━━
🤖 AI Coach

${safeTelegramAi}
━━━━━━━━━━━━━━━━━
_Amazfit Helio → n8n → AI Coach_`;

return [{ json: { htmlEmail, whatsappMsg: telegramMsg, report_date: reportDate } }];
